						CommUtils.outred("hold | Risposta: hold COMPLETA")
						 
						        val holdStatus = slots.entries.joinToString(", ") { "${it.key}=${it.value}" }
						        mqtt.publish("cargo/display/msg", "Hold: $holdStatus (PIENA)")
						answer("find_free_slot", "slot_full", "slotFull(none)"   )  
