						            slots[SlotToOccupy] = "occupied" 
						            val holdStatus = slots.entries.joinToString(", ") { "${it.key}=${it.value}" }
						            mqtt.publish("cargo/display/msg", "Hold: $holdStatus")
						CommUtils.outgreen("hold | $SlotToOccupy ora OCCUPATO")
						}
						else
						 {CommUtils.outred("hold | ANOMALIA: $SlotToOccupy già occupato, richiesta ignorata")
						 }
						answer("find_occupy", "occupy_done", "occupySlotDone(none)"   )  
						//genTimer( actor, state )
					}
					//After Lenzi Aug2002
					sysaction { //it:State
					}	 	 
					 transition( edgeName="goto",targetState="idle", cond=doswitch() )
				}	 
				state("free_slot") { //this:State
					action { //it:State
						if( checkMsgContent( Term.createTerm("releaseSlot(SLOTID)"), Term.createTerm("releaseSlot(SLOTID)"), 
						                        currentMsg.msgContent()) ) { //set msgArgList
								 
								            val SlotToRelease = payloadArg(0).toString()
								            slots[SlotToRelease] = "free" 
								            val holdStatus = slots.entries.joinToString(", ") { "${it.key}=${it.value}" }
								            mqtt.publish("cargo/display/msg", "Hold: $holdStatus")
								CommUtils.outyellow("hold | Rilasciato $SlotToRelease")
								answer("find_release", "release_done", "releaseSlotDone(none)"   )  
						}
						//genTimer( actor, state )
					}
					//After Lenzi Aug2002
					sysaction { //it:State
					}	 	 
					 transition( edgeName="goto",targetState="idle", cond=doswitch() )
